(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[4692],{8468:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-178acfa6",path:"/python/data-type/string/format/",title:"String Format",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"F string method",slug:"f-string-method",children:[{level:3,title:"How to use F String",slug:"how-to-use-f-string",children:[]}]},{level:2,title:".format() method",slug:"format-method",children:[{level:3,title:"How to use .format()",slug:"how-to-use-format",children:[]}]},{level:2,title:"% formatting",slug:"formatting",children:[{level:3,title:"ตั้งการมี Space",slug:"ตั้งการมี-space",children:[]},{level:3,title:"ตัดความยาว String",slug:"ตัดความยาว-string",children:[]}]},{level:2,title:"String with ASCII",slug:"string-with-ascii",children:[{level:3,title:"การเปลี่ยน String ไปเป็น ASCII โดยใช้ ord()",slug:"การเปลี่ยน-string-ไปเป็น-ascii-โดยใช้-ord",children:[]},{level:3,title:"การเปลี่ยน ASCII ไปเป็น String โดยใช้ chr()",slug:"การเปลี่ยน-ascii-ไปเป็น-string-โดยใช้-chr",children:[]}]},{level:2,title:"String to change case",slug:"string-to-change-case",children:[{level:3,title:"Using .lower()",slug:"using-lower",children:[]},{level:3,title:"Using .upper()",slug:"using-upper",children:[]},{level:3,title:"Using .swapcase()",slug:"using-swapcase",children:[]},{level:3,title:"Using .isupper() & .islower()",slug:"using-isupper-islower",children:[]},{level:3,title:"Using .isdigit() & .isalpha()",slug:"using-isdigit-isalpha",children:[]}]}],filePathRelative:"python/data-type/string/format/README.md",git:{updatedTime:162676698e4,contributors:[]}}},4060:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>h});var e=a(6252);const t=(0,e.uE)('<h1 id="string-format" tabindex="-1"><a class="header-anchor" href="#string-format" aria-hidden="true">#</a> String Format</h1><p>เนื่องจากว่า บางครั้ง น้องๆอยากที่จะใช้ Python เพื่อการแสดงผลลัพท์ แต่ก็อยากให้มันเป็น Format หรือ การเรียงตัวอักษรที่น้องต้องการ<br> จึงทำให้ น้องขี้เกียจมาพิมพ์แบบนี้</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token number">21</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Kumamon is already&quot;</span><span class="token punctuation">,</span> var1<span class="token punctuation">,</span> <span class="token string">&quot;years old&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>เพื่อจะได้ผลลัพท์ &quot;Kumamon is already 21 years old&quot;</p><p>วันนี้ พี่มงจึงมาสอนการใข้ <code>%</code> และ <code>.format()</code> และ <code>f string</code> ครับ</p><h2 id="f-string-method" tabindex="-1"><a class="header-anchor" href="#f-string-method" aria-hidden="true">#</a> F string method</h2>',6),p={class:"custom-container tip"},o=(0,e.Wm)("p",{class:"custom-container-title"},"NOTE",-1),r=(0,e.Uk)("การใช้ F String นี้ได้เพื่มมาใน Python เวอร์ชั่น 3.6 ครับ (Reference "),c={href:"https://www.python.org/dev/peps/pep-0498/",target:"_blank",rel:"noopener noreferrer"},l=(0,e.Uk)("PIP 498"),i=(0,e.Uk)(") ดังนั้นน้องๆจำเป็นที่จะต้องใช้ Python เวอร์ชั่นอย่างน้อย 3.6 ขึ้นไป เพื่อจะใช้ method นี้ได้ครับ"),u=(0,e.uE)('<p>ในวิธีนี้ เป็นฟีเจอร์ของ Python3 ที่ต้องการที่จะผู้ใช้งานไม่ต้องไปดูว่าในลำดับไหน ใช้ค่าผลลัพท์ตัวแปรอันไหน</p><p>ตัวอย่างการใช้งาน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>text <span class="token operator">=</span> <span class="token string">&quot;Kumamon&quot;</span>\nnumber_one <span class="token operator">=</span> <span class="token number">2</span>\nnumber_two <span class="token operator">=</span> <span class="token number">1</span>\nnumber_three <span class="token operator">=</span> <span class="token number">2.99</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&quot;The answer is </span><span class="token interpolation"><span class="token punctuation">{</span>number_one<span class="token punctuation">}</span></span><span class="token string"> + </span><span class="token interpolation"><span class="token punctuation">{</span>number_two<span class="token punctuation">}</span></span><span class="token string"> = </span><span class="token interpolation"><span class="token punctuation">{</span>number_three<span class="token punctuation">}</span></span><span class="token string">. Calculated by </span><span class="token interpolation"><span class="token punctuation">{</span>text<span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>โอ้โห อ่านง่ายขึ้นเยอะเลย แต่ปัญหาคือ จะได้ผลลัพท์ที่ถูกต้องหรือเปล่าเอ่ย?</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>Python 3.7.0 (default, Oct  2 2018, 09:18:58)\n[Clang 10.0.0 (clang-1000.11.45.2)] on darwin\n\n&gt;&gt;&gt; text = &quot;Kumamon&quot;\n&gt;&gt;&gt; number_one = 2\n&gt;&gt;&gt; number_two = 1\n&gt;&gt;&gt; number_three = 2.99\n&gt;&gt;&gt; print(f&quot;The answer is {number_one} + {number_two} = {number_three}. Calculated by {text}&quot;)\n\nThe answer is 2 + 1 = 2.99. Calculated by Kumamon\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>โอ้ววววว ใช้ง่ายแบบนี้ต้องสอนวิธีการใช้ซะแล้ว</p><h3 id="how-to-use-f-string" tabindex="-1"><a class="header-anchor" href="#how-to-use-f-string" aria-hidden="true">#</a> How to use F String</h3><p>การใช้ก็ง่ายมากเลย โดยให้ใส่ตัวอักษร <code>f</code> (เอฟ) โดยจะเป็นตัวพิมพ์เล็ก หรือ พิมพ์ใหญ่ก็ได้ครับก่อนหน้า string <code>&quot;&quot;</code> หรือ <code>&#39;&#39;</code></p><p>และการเอาตัวแปรไปยัด ก็ให้ใช้ปีกกา <code>{}</code> เพื่อบอกว่าจุดนั้นคือจุดที่ตัวแปรจะไปอยู่นั่นเอง</p><p>หากใช่ง่ายแบบนี้ ก็ลองไปใช้ดูนะครับ</p><h2 id="format-method" tabindex="-1"><a class="header-anchor" href="#format-method" aria-hidden="true">#</a> <code>.format()</code> method</h2><p>การใช้ method นี้ก็เพื่อทำการนำค่าในตัวแปรไปอยู่ใน string โดยที่ไม่ต้องไปทำอะไรเยอะแยะ แต่เราก็ยังต้องทำการบอกว่า ตัวแปรไหน มีค่าเท่าไหร่ และอยู่ในลำดับไหน</p><h3 id="how-to-use-format" tabindex="-1"><a class="header-anchor" href="#how-to-use-format" aria-hidden="true">#</a> How to use <code>.format()</code></h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>ตอนนี้พี่มงขอไม่เขียนก็แล้วกันนะครับ เพราะว่าอยากให้น้องไปใช้ F String กัน อิอิ</p></div><h2 id="formatting" tabindex="-1"><a class="header-anchor" href="#formatting" aria-hidden="true">#</a> <code>%</code> formatting</h2><p>เอาจริงๆ มันก็คือเครื่องหมายเปอร์เซ็นต์นั่นแหละครับ แต่ก็ทำให้มันเป็น <strong>ที่วางตัวแปร</strong> ได้เช่นเดียวกัน</p><p>อันนี้เป็นวิธีการใช้งานครับ น้องๆอาจจะยังไม่เข้าใจก็ไม่เป็นไร ค่อยกลับมาดูก็ได้ครับ</p><table><thead><tr><th style="text-align:left;"><strong>ใช้</strong></th><th>%s</th><th>%d</th><th>%f</th><th>%e</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>เพื่อแสดงตัวแปรประเภท</strong></td><td>String</td><td>Integer</td><td>Float</td><td>เลขฐานในหลักวิทยาศาสตร์<br>(Scientific Significant)</td></tr></tbody></table><p>ตัวอย่างการใช้งาน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>age <span class="token operator">=</span> <span class="token number">21</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Kumamon is already %d years old&quot;</span> <span class="token operator">%</span>age<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>ก็จะได้ผลลัพท์ &quot;Kumamon is already 21 years old&quot; เช่นเดียวกันครับ</p><p>โดยหลักการคร่าวๆนั่นก็คือ Python จะทำการเอาตัวแปร <code>age</code> เข้าไปยัดในจุดที่ <code>%d</code> อ ยู่ ทำให้ได้ผลลัพท์ได้ออกมาแบบนั้นครับ</p><p>แล้วถ้าพี่อยากใส่มากกว่า 1 ตัวหล่ะ เช่น &quot;My name is <code>&lt;first_name&gt;</code> and my age is <code>&lt;age&gt;</code> years old&quot; โดยตัวแปร <code>&lt;first_name&gt;</code> และ <code>&lt;age&gt;</code> พี่จะกำหนดค่าตัวแปรเอง</p><p>หากว่าพี่ใช้วิธีโบราณ ด้วยการเอาไปแปะ (Concat) ก็ได้เขียนได้ดังนี้ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>first_name <span class="token operator">=</span> <span class="token string">&quot;Kumamon&quot;</span>\nage <span class="token operator">=</span> <span class="token number">21</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;My name is&quot;</span><span class="token punctuation">,</span> first_name<span class="token punctuation">,</span> <span class="token string">&quot;and my age is&quot;</span><span class="token punctuation">,</span> age<span class="token punctuation">,</span> <span class="token string">&quot;years old&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ซึ่งก็เขียนยากซะเหลือเกิน อิอิ</p><p>แต่เมื่อน้องเรียนการใช้ <code>%</code> แล่้ว น้องๆก็สามารถใช้ <code>%</code> ได้ดังนี้ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>first_name <span class="token operator">=</span> <span class="token string">&quot;Kumamon&quot;</span>\nage <span class="token operator">=</span> <span class="token number">21</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;My name is %s and my age is %d years old&quot;</span> <span class="token operator">%</span><span class="token punctuation">(</span>first_name<span class="token punctuation">,</span> age<span class="token punctuation">)</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ก็จะได้ผลลัพท์เป็น &quot;My name is Kumamon and my age is 21 years old&quot; นั่นเอง</p><p>เห็นมั้ยครับ ว่ามันง่ายขึ้นเยอะ<br> ส่วนน้องๆที่บอกว่า &quot;พี่มงขี้โม้ มันยากกว่าเดิมหนิพี่&quot; ก็คิดว่ามันง่ายกว่าเดิมละกันครับ และพี่ก็ไม่ได้โม้ เพราะเรายังไม่จบแค่นี้ครับ</p><h3 id="ตั้งการมี-space" tabindex="-1"><a class="header-anchor" href="#ตั้งการมี-space" aria-hidden="true">#</a> ตั้งการมี Space</h3><p>และโจทย์ต่อไปก็คือการกำหนดขนาดของมันนั่นเอง เพราะถ้าเราสามารถกำหนดขนาด โดยการใช้ [] ได้แล้ว พี่มงก็ว่า เราสามารถทำกับ % ได้เช่นเดียวกัน</p><p>แต่เนื่องจากว่า Python ก็ได้จัดการทำ Aligment มาให้ด้วย<br> เช่นต้องการให้เป็นแบบนี้</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>My Name is Kumamon              naja\nMy Name is              Kumamon naja          \n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>นั่นก็คือการให้มันชิดขวา และ ชิดซ้ายนั่นเอง</p><p>น้องๆก็สามารถทำให้มันชิดได้ โดยการใส่ตัวเลขไปด้วย<br> ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>first_name <span class="token operator">=</span> <span class="token string">&quot;Kumamon&quot;</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;My Name is %-20s naja&quot;</span> <span class="token operator">%</span>first_name<span class="token punctuation">)</span>   \n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;My Name is %20s naja&quot;</span> <span class="token operator">%</span>first_name<span class="token punctuation">)</span> \n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>ก็จะได้ผลลัพท์เหมือนด้านบนครับ</p><p>โดยหลักการนั่นก็คือ Python จะเว้นที่ไว้ x ช่อง (ซึ่งในตัวอย่างเว้นไว้ 20 ช่่อง)<br> แล้วค่อยใส่ String ไปตรงนั้น</p><p>โดยหากว่า</p><ul><li>เป็นเลขจำนวนเป็นบวก ก็จะชิดขวา</li><li>เป็นเลขจำนวนเป็นลบ ก็จะชิดซ้าย</li></ul><h3 id="ตัดความยาว-string" tabindex="-1"><a class="header-anchor" href="#ตัดความยาว-string" aria-hidden="true">#</a> ตัดความยาว String</h3><p>หลังจากได้เรียนการ align กันมาแล้ว ก็จะบอกว่ายังมี function นึงที่น้องๆอาจจะยังไม่เคยเจอ นั่นก็คือการตัดให้ได้ขนาด x ตัว</p><p>ไปดูตัวอย่างกันครับ</p><p>โดยปกติแล้ว เราก็จะใช้ [] แบบนี้</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>first_name <span class="token operator">=</span> <span class="token string">&quot;Kumamon&quot;</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;My name is&quot;</span><span class="token punctuation">,</span> first_name<span class="token punctuation">[</span><span class="token punctuation">:</span><span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>ก็จะได้ผลออกมาเป็น &quot;My name is Kuma&quot; นั่นเอง</p><p>ซึ่งตัว <code>%</code> ก็ทำได้เช่นกันครับ ดังตัวอย่างข้างล่าง</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>first_name <span class="token operator">=</span> <span class="token string">&quot;Kumamon&quot;</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;My name is %s&quot;</span><span class="token punctuation">,</span> <span class="token operator">%</span>first_name<span class="token punctuation">[</span><span class="token punctuation">:</span><span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>',49),d=(0,e.Uk)("แต่ก็ยังไม่"),m={href:"https://www.youtube.com/watch?v=LKLH2E7uaMY",target:"_blank",rel:"noopener noreferrer"},k=(0,e.Uk)("สุดๆไปเลย เหมือนเพลงของนูโว"),b=(0,e.Uk)(" เพราะยังทำแบบนี้ได้อีกครับ"),g=(0,e.uE)('<div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>first_name <span class="token operator">=</span> <span class="token string">&quot;Kumamon&quot;</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;My name is %.4s&quot;</span><span class="token punctuation">,</span> <span class="token operator">%</span>first_name<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>แต่ต้องเตือนไว้ก่อน ว่าถ้าใส่ตัวเลขไปมากกว่าที่ array string มีอยู่ ก็จะเป็นแบบนี้ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="string-with-ascii" tabindex="-1"><a class="header-anchor" href="#string-with-ascii" aria-hidden="true">#</a> String with ASCII</h2><p><img src="https://i.stack.imgur.com/X4yts.png" alt="https://i.stack.imgur.com/X4yts.png"><em>Reference : https://i.stack.imgur.com/X4yts.png</em></p><p>ต้องอธิบายก่อนว่า ปกติแล้วโปรแกรมคอมพิวเตอร์ทุกอัน ได้ทำการเปลี่ยนการจัดเก็บข้อมูลแบบ string หรือ character ให้มาเป็นตัวเลขทั้งหมด เพื่อจะเอาไปเก็บเป็น binary ทีหลัง</p><p>ดังนั้น ASCII จึงเกิดขึ้น โดยการบอกให้ว่า เลขนี้ เท่ากับตัวอักษรอะไร และตัว Python จึงไปทำการคำนวณต่อ ว่าให้ทำอะไรต่อไป</p><p>ดังนั้นวันนี้เราจะมาลองเล่นดูครับ</p><h3 id="การเปลี่ยน-string-ไปเป็น-ascii-โดยใช้-ord" tabindex="-1"><a class="header-anchor" href="#การเปลี่ยน-string-ไปเป็น-ascii-โดยใช้-ord" aria-hidden="true">#</a> การเปลี่ยน String ไปเป็น ASCII โดยใช้ <code>ord()</code></h3><p>การเปลี่ยน character ไปเป็น ASCII ก็สามารถทำได้ง่ายๆ โดยการใช้ function <code>ord()</code> ครับ และใส่ character ไปเป็น input parameter ของฟังก์ชั่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">ord</span><span class="token punctuation">(</span><span class="token string">&#39;A&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>         <span class="token comment"># Print out 65</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">ord</span><span class="token punctuation">(</span><span class="token string">&#39;B&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>         <span class="token comment"># Print out 66</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">ord</span><span class="token punctuation">(</span><span class="token string">&#39;A&#39;</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span>     <span class="token comment"># Print out 66</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="การเปลี่ยน-ascii-ไปเป็น-string-โดยใช้-chr" tabindex="-1"><a class="header-anchor" href="#การเปลี่ยน-ascii-ไปเป็น-string-โดยใช้-chr" aria-hidden="true">#</a> การเปลี่ยน ASCII ไปเป็น String โดยใช้ <code>chr()</code></h3><p>เปลี่ยนตัวเลข (ย้ำว่าควรเป็นประเภท integer อยู่) ก็สามารถทำได้โดยการใช้ฟังก์ชั่น <code>chr()</code> และใส่ตัวเลขเข้าไปเป็น input parameter ของฟังก์ชั่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">chr</span><span class="token punctuation">(</span><span class="token number">65</span><span class="token punctuation">)</span><span class="token punctuation">)</span>      <span class="token comment"># Print out &#39;A&#39;</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">chr</span><span class="token punctuation">(</span><span class="token number">65</span><span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span>    <span class="token comment"># Print out &#39;B&#39;</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">chr</span><span class="token punctuation">(</span><span class="token number">65</span><span class="token operator">+</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">)</span>    <span class="token comment"># Print out &#39;C&#39;</span>\n\nvar <span class="token operator">=</span> <span class="token number">65</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">chr</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment"># Print out &#39;A&#39;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="string-to-change-case" tabindex="-1"><a class="header-anchor" href="#string-to-change-case" aria-hidden="true">#</a> String to change case</h2><p>เปลี่ยนตัวอักษรไปเป็น lowercase <code>.lower()</code> <br> เปลี่ยนตัวอักษรไปเป็น uppercase <code>.upper()</code> <br> สลับตัวอักษรระหว่าง lower/upper <code>.swapcase()</code> <br></p><p>เช็คว่าตัวอักษรนั้นเป็น lowercase ทั้งหมดหรือไม่ <code>.islower()</code> <br> เช็คว่าตัวอักษรนั้นเป็น uppercase ทั้งหมดหรือไม่ <code>.isupper()</code> <br> เช็คว่าตัวอักษรนั้นเป็นตัวเลขทั้งหมดหรือไม่ <code>.isdigit()</code> <br> เช็คว่าตัวอักษรนั้นเป็นตัวอักษรทั้งหมดหรือไม่ <code>.isalpha()</code> <br></p><h3 id="using-lower" tabindex="-1"><a class="header-anchor" href="#using-lower" aria-hidden="true">#</a> Using .lower()</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">return</span> text<span class="token punctuation">.</span>lower<span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token comment"># If text = &quot;KUMAMON&quot;, returns &quot;kumamon&quot;</span>\n<span class="token comment"># If text = &quot;KuMaMoN&quot;, returns &quot;kumamon&quot;</span>\n<span class="token comment"># If text = &quot;kumamon&quot;, returns &quot;kumamon&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="using-upper" tabindex="-1"><a class="header-anchor" href="#using-upper" aria-hidden="true">#</a> Using .upper()</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">return</span> text<span class="token punctuation">.</span>upper<span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token comment"># If text = &quot;KUMAMON&quot;, returns &quot;KUMAMON&quot;</span>\n<span class="token comment"># If text = &quot;KuMaMoN&quot;, returns &quot;KUMAMON&quot;</span>\n<span class="token comment"># If text = &quot;kumamon&quot;, returns &quot;KUMAMON&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="using-swapcase" tabindex="-1"><a class="header-anchor" href="#using-swapcase" aria-hidden="true">#</a> Using .swapcase()</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">return</span> text<span class="token punctuation">.</span>swapcase<span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token comment"># If text = &quot;KUMAMON&quot;, returns &quot;kumamon&quot;</span>\n<span class="token comment"># If text = &quot;KuMaMoN&quot;, returns &quot;kUmAmOn&quot;</span>\n<span class="token comment"># If text = &quot;kumamon&quot;, returns &quot;KUMAMON&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="using-isupper-islower" tabindex="-1"><a class="header-anchor" href="#using-isupper-islower" aria-hidden="true">#</a> Using .isupper() &amp; .islower()</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token operator">&lt;</span>string<span class="token operator">&gt;</span><span class="token punctuation">.</span>islower<span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token operator">&lt;</span>string<span class="token operator">&gt;</span><span class="token punctuation">.</span>isupper<span class="token punctuation">(</span><span class="token punctuation">)</span>\n\ntext <span class="token operator">=</span> <span class="token string">&quot;K&quot;</span>\n<span class="token keyword">return</span> text<span class="token punctuation">.</span>islower<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># Returns false</span>\n<span class="token keyword">return</span> text<span class="token punctuation">.</span>isupper<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># Returns true</span>\n\ntext <span class="token operator">=</span> <span class="token string">&quot;k&quot;</span>\n<span class="token keyword">return</span> text<span class="token punctuation">.</span>islower<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># Returns true</span>\n<span class="token keyword">return</span> text<span class="token punctuation">.</span>isupper<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># Returns false</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="using-isdigit-isalpha" tabindex="-1"><a class="header-anchor" href="#using-isdigit-isalpha" aria-hidden="true">#</a> Using .isdigit() &amp; .isalpha()</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>How to use<span class="token punctuation">:</span>\n<span class="token operator">&lt;</span><span class="token builtin">input</span> variable<span class="token operator">&gt;</span><span class="token punctuation">.</span>isdigit<span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token operator">-</span><span class="token operator">&gt;</span> Returns <span class="token boolean">True</span> <span class="token keyword">or</span> <span class="token boolean">False</span>\n\n<span class="token operator">&lt;</span><span class="token builtin">input</span> variable<span class="token operator">&gt;</span><span class="token punctuation">.</span>isalpha<span class="token punctuation">(</span><span class="token punctuation">)</span>\n<span class="token operator">-</span><span class="token operator">&gt;</span> Returns <span class="token boolean">True</span> <span class="token keyword">or</span> <span class="token boolean">False</span>\n\ntext <span class="token operator">=</span> <span class="token string">&quot;12&quot;</span>\n<span class="token keyword">return</span> text<span class="token punctuation">.</span>isdigit<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># Returns true</span>\n<span class="token keyword">return</span> text<span class="token punctuation">.</span>isalpha<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># Returns false</span>\n\ntext <span class="token operator">=</span> <span class="token string">&quot;ABC&quot;</span>\n<span class="token keyword">return</span> text<span class="token punctuation">.</span>isdigit<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># Returns false</span>\n<span class="token keyword">return</span> text<span class="token punctuation">.</span>isalpha<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># Returns true</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div>',27),h={render:function(n,s){const a=(0,e.up)("OutboundLink");return(0,e.wg)(),(0,e.j4)(e.HY,null,[t,(0,e.Wm)("div",p,[o,(0,e.Wm)("p",null,[r,(0,e.Wm)("a",c,[l,(0,e.Wm)(a)]),i])]),u,(0,e.Wm)("p",null,[d,(0,e.Wm)("a",m,[k,(0,e.Wm)(a)]),b]),g],64)}}}}]);